        }
        return res;
    }
    private int lis(List<Integer> nums) {
        List<Integer> tails = new ArrayList<>();
        for (int x : nums) {
            int idx = upperBound(tails, x);
            if (idx == tails.size()) tails.add(x);
            else tails.set(idx, x);
        }
        return tails.size();
    }
    private int upperBound(List<Integer> list, int key) {
        int lo = 0, hi = list.size();
        while (lo < hi) {
            int mid = (lo + hi) >>> 1;
            if (list.get(mid) <= key) lo = mid + 1;
            else hi = mid;
        }
        return lo;
    }
